pub fn mean_flow_magnitude(field: &MotionField) -> f32 {
    if field.vectors.is_empty() {
        return 0.0;
    }
    let sum: f32 = field.vectors.iter()
        .map(|[dx, dy]| (dx * dx + dy * dy).sqrt())
        .sum();
    sum / field.vectors.len() as f32
}
